impl Solution { pub fn max_subarray_sum_circular(black_nums: Vec<i32>) -> i32 { let (mut black_max, mut black_min, mut black_cur_max, mut black_cur_min, mut black_total) = (black_nums[0], black_nums[0], 0, 0, 0); for &x in &black_nums { black_cur_max = x.max(black_cur_max + x); black_max = black_max.max(black_cur_max); black_cur_min = x.min(black_cur_min + x); black_min = black_min.min(black_cur_min); black_total += x; } if black_max > 0 { black_max.max(black_total - black_min) } else { black_max } } }
